 17→// Session state management functions shared across all strategies.
 18→// SessionState is stored in .git/entire-sessions/{session_id}.json
 19→
 20→// getSessionStateDir returns the path to the session state directory.
 21→// This is stored in the git common dir so it's shared across all worktrees.
 22→func getSessionStateDir() (string, error) {
 23→	commonDir, err := GetGitCommonDir()
 24→	if err != nil {
 25→		return "", err
 26→	}
 27→	return filepath.Join(commonDir, session.SessionStateDirName), nil
 28→}
 29→
 30→// sessionStateFile returns the path to a session state file.
 31→func sessionStateFile(sessionID string) (string, error) {
 32→	stateDir, err := getSessionStateDir()
 33→	if err != nil {
 34→		return "", err
 35→	}
 36→	return filepath.Join(stateDir, sessionID+".json"), nil
 37→}
 38→
 39→// LoadSessionState loads the session state for the given session ID.
 40→// Returns (nil, nil) when session file doesn't exist (not an error condition).
 41→func LoadSessionState(sessionID string) (*SessionState, error) {
 42→	// Validate session ID to prevent path traversal
 43→	if err := validation.ValidateSessionID(sessionID); err != nil {
 44→		return nil, fmt.Errorf("invalid session ID: %w", err)
 45→	}
 46→
 47→	stateFile, err := sessionStateFile(sessionID)
 48→	if err != nil {
 49→		return nil, fmt.Errorf("failed to get session state file path: %w", err)
 50→	}
 51→
 52→	data, err := os.ReadFile(stateFile) //nolint:gosec // stateFile is derived from sessionID, not user input
 53→	if os.IsNotExist(err) {
 54→		return nil, nil //nolint:nilnil // nil,nil indicates session not found (expected case)
 55→	}
 56→	if err != nil {
 57→		return nil, fmt.Errorf("failed to read session state: %w", err)
 58→	}
 59→
 60→	var state SessionState
 61→	if err := json.Unmarshal(data, &state); err != nil {
 62→		return nil, fmt.Errorf("failed to unmarshal session state: %w", err)
 63→	}
 64→	state.NormalizeAfterLoad()
 65→
 66→	if state.IsStale() {
 67→		logCtx := logging.WithComponent(context.Background(), "session")
 68→		logging.Debug(logCtx, "deleting stale session state",
 69→			slog.String("session_id", sessionID),
 70→		)
 71→		_ = ClearSessionState(sessionID) //nolint:errcheck // best-effort cleanup of stale session
 72→		return nil, nil                  //nolint:nilnil // stale session treated as not found
 73→	}
 74→
 75→	return &state, nil
 76→}
