 78→// SaveSessionState saves the session state atomically.
 79→func SaveSessionState(state *SessionState) error {
 80→	// Validate session ID to prevent path traversal
 81→	if err := validation.ValidateSessionID(state.SessionID); err != nil {
 82→		return fmt.Errorf("invalid session ID: %w", err)
 83→	}
 84→
 85→	stateDir, err := getSessionStateDir()
 86→	if err != nil {
 87→		return fmt.Errorf("failed to get session state directory: %w", err)
 88→	}
 89→
 90→	if err := os.MkdirAll(stateDir, 0o750); err != nil {
 91→		return fmt.Errorf("failed to create session state directory: %w", err)
 92→	}
 93→
 94→	data, err := jsonutil.MarshalIndentWithNewline(state, "", "  ")
 95→	if err != nil {
 96→		return fmt.Errorf("failed to marshal session state: %w", err)
 97→	}
 98→
 99→	stateFile, err := sessionStateFile(state.SessionID)
100→	if err != nil {
101→		return fmt.Errorf("failed to get session state file path: %w", err)
102→	}
103→
104→	// Atomic write: write to temp file, then rename
105→	tmpFile := stateFile + ".tmp"
106→	if err := os.WriteFile(tmpFile, data, 0o600); err != nil {
107→		return fmt.Errorf("failed to write session state: %w", err)
108→	}
109→	if err := os.Rename(tmpFile, stateFile); err != nil {
110→		return fmt.Errorf("failed to rename session state file: %w", err)
111→	}
112→	return nil
113→}
