115→// ListSessionStates returns all session states from the state directory.
116→// This is a package-level function that doesn't require a specific strategy instance.
117→func ListSessionStates() ([]*SessionState, error) {
118→	store, err := session.NewStateStore()
119→	if err != nil {
120→		return nil, fmt.Errorf("failed to create state store: %w", err)
121→	}
122→
123→	states, err := store.List(context.Background())
124→	if err != nil {
125→		return nil, fmt.Errorf("failed to list session states: %w", err)
126→	}
127→	return states, nil
128→}
