130→// FindMostRecentSession returns the session ID of the most recently interacted session
131→// (by LastInteractionTime) in the current worktree. Returns empty string if no sessions exist.
132→// Scoping to the current worktree prevents cross-worktree pollution in log routing.
133→// Falls back to unfiltered search if the worktree path can't be determined.
134→func FindMostRecentSession() string {
135→	states, err := ListSessionStates()
136→	if err != nil || len(states) == 0 {
137→		return ""
138→	}
139→
140→	// Scope to current worktree to prevent cross-worktree pollution.
141→	worktreePath, wpErr := GetWorktreePath()
142→	if wpErr == nil && worktreePath != "" {
143→		var filtered []*SessionState
144→		for _, s := range states {
145→			if s.WorktreePath == worktreePath {
146→				filtered = append(filtered, s)
147→			}
148→		}
149→		if len(filtered) > 0 {
150→			states = filtered
151→		}
152→		// If no sessions match the worktree, fall back to all sessions
153→	}
154→
155→	var best *SessionState
156→	for _, s := range states {
157→		if s.LastInteractionTime == nil {
158→			continue
159→		}
160→		if best == nil || s.LastInteractionTime.After(*best.LastInteractionTime) {
161→			best = s
162→		}
163→	}
164→	if best != nil {
165→		return best.SessionID
166→	}
167→
168→	// Fallback: return most recently started session
169→	for _, s := range states {
170→		if best == nil || s.StartedAt.After(best.StartedAt) {
171→			best = s
172→		}
173→	}
174→	if best != nil {
175→		return best.SessionID
176→	}
177→	return ""
178→}
