180→// TransitionAndLog runs a session phase transition, applies actions via the
181→// handler, and logs the transition. Returns the first handler error from
182→// ApplyTransition (if any) so callers can surface it. The error is also
183→// logged internally for diagnostics.
184→// This is the single entry point for all state machine transitions to ensure
185→// consistent logging of phase changes.
186→func TransitionAndLog(state *SessionState, event session.Event, ctx session.TransitionContext, handler session.ActionHandler) error {
187→	oldPhase := state.Phase
188→	result := session.Transition(oldPhase, event, ctx)
189→	logCtx := logging.WithComponent(context.Background(), "session")
190→
191→	handlerErr := session.ApplyTransition(state, result, handler)
192→	if handlerErr != nil {
193→		logging.Error(logCtx, "action handler error during transition",
194→			slog.String("session_id", state.SessionID),
195→			slog.String("event", event.String()),
196→			slog.Any("error", handlerErr),
197→		)
198→	}
199→
200→	if result.NewPhase != oldPhase {
201→		logging.Info(logCtx, "phase transition",
202→			slog.String("session_id", state.SessionID),
203→			slog.String("event", event.String()),
204→			slog.String("from", string(oldPhase)),
205→			slog.String("to", string(result.NewPhase)),
206→		)
207→	} else {
208→		logging.Debug(logCtx, "phase unchanged",
209→			slog.String("session_id", state.SessionID),
210→			slog.String("event", event.String()),
211→			slog.String("phase", string(result.NewPhase)),
212→			slog.Any("result", result),
213→		)
214→	}
215→
216→	if handlerErr != nil {
217→		return fmt.Errorf("transition %s: %w", event, handlerErr)
218→	}
219→	return nil
220→}
