222→// ClearSessionState removes the session state file for the given session ID.
223→func ClearSessionState(sessionID string) error {
224→	// Validate session ID to prevent path traversal
225→	if err := validation.ValidateSessionID(sessionID); err != nil {
226→		return fmt.Errorf("invalid session ID: %w", err)
227→	}
228→
229→	stateFile, err := sessionStateFile(sessionID)
230→	if err != nil {
231→		return fmt.Errorf("failed to get session state file path: %w", err)
232→	}
233→
234→	if err := os.Remove(stateFile); err != nil {
235→		if os.IsNotExist(err) {
236→			return nil // Already gone, not an error
237→		}
238→		return fmt.Errorf("failed to remove session state file: %w", err)
239→	}
240→	return nil
241→}
