 58→// listAllSessionStates returns all active session states.
 59→// It filters out orphaned sessions whose shadow branch no longer exists.
 60→func (s *ManualCommitStrategy) listAllSessionStates() ([]*SessionState, error) {
 61→	store, err := s.getStateStore()
 62→	if err != nil {
 63→		return nil, fmt.Errorf("failed to get state store: %w", err)
 64→	}
 65→
 66→	sessionStates, err := store.List(context.Background())
 67→	if err != nil {
 68→		return nil, fmt.Errorf("failed to list session states: %w", err)
 69→	}
 70→
 71→	if len(sessionStates) == 0 {
 72→		return nil, nil
 73→	}
 74→
 75→	repo, err := OpenRepository()
 76→	if err != nil {
 77→		return nil, fmt.Errorf("failed to open git repository: %w", err)
 78→	}
 79→
 80→	var states []*SessionState
 81→	for _, sessionState := range sessionStates {
 82→		state := sessionState
 83→
 84→		// Skip and cleanup orphaned sessions whose shadow branch no longer exists.
 85→		// Keep active sessions (shadow branch may not be created yet) and sessions
 86→		// with LastCheckpointID (needed for checkpoint ID reuse on subsequent commits).
 87→		// Clean up everything else: stale pre-state-machine sessions (empty phase),
 88→		// IDLE/ENDED sessions that were never condensed, etc.
 89→		shadowBranch := getShadowBranchNameForCommit(state.BaseCommit, state.WorktreeID)
 90→		refName := plumbing.NewBranchReferenceName(shadowBranch)
 91→		if _, err := repo.Reference(refName, true); err != nil {
 92→			if !state.Phase.IsActive() && state.LastCheckpointID.IsEmpty() {
 93→				//nolint:errcheck,gosec // G104: Cleanup is best-effort, shouldn't fail the list operation
 94→				store.Clear(context.Background(), state.SessionID)
 95→				continue
 96→			}
 97→		}
 98→
 99→		states = append(states, state)
100→	}
101→	return states, nil
102→}
