148→// CountOtherActiveSessionsWithCheckpoints counts how many other active sessions
149→// from the SAME worktree (different from currentSessionID) have created checkpoints
150→// on the SAME base commit (current HEAD). This is used to show an informational message
151→// about concurrent sessions that will be included in the next commit.
152→// Returns 0, nil if no such sessions exist.
153→func (s *ManualCommitStrategy) CountOtherActiveSessionsWithCheckpoints(currentSessionID string) (int, error) {
154→	currentWorktree, err := GetWorktreePath()
155→	if err != nil {
156→		return 0, err
157→	}
158→
159→	// Get current HEAD to compare with session base commits
160→	repo, err := OpenRepository()
161→	if err != nil {
162→		return 0, err
163→	}
164→	head, err := repo.Head()
165→	if err != nil {
166→		return 0, fmt.Errorf("failed to get HEAD: %w", err)
167→	}
168→	currentHead := head.Hash().String()
169→
170→	allStates, err := s.listAllSessionStates()
171→	if err != nil {
172→		return 0, err
173→	}
174→
175→	count := 0
176→	for _, state := range allStates {
177→		// Only consider sessions from the same worktree with checkpoints
178→		// AND based on the same commit (current HEAD)
179→		// Sessions from different base commits are independent and shouldn't be counted
180→		if state.SessionID != currentSessionID &&
181→			state.WorktreePath == currentWorktree &&
182→			state.StepCount > 0 &&
183→			state.BaseCommit == currentHead {
184→			count++
185→		}
186→	}
187→	return count, nil
188→}
